class StudyTimer:
    def __init__(self, name):
        self.name = name
        self.minutes = 0

    def add(self, minutes):
        self.minutes += minutes

    def label(self):
        return f"{self.name}: {self.minutes} min"

timer = StudyTimer("Python")
timer.add(20)
print(timer.label())
timer.add(10)
print(timer.label())
